export type AssetState =
  | { status: "none" }
  | { status: "active"; id: string; value: number }
  | { status: "retired"; id: string; finalValue: number };

export type AssetCommand =
  | { type: "register"; id: string; value: number }
  | { type: "revalue"; value: number }
  | { type: "retire" };

export type AssetEvent =
  | { type: "AssetRegistered"; id: string; value: number }
  | { type: "AssetRevalued"; value: number }
  | { type: "AssetRetired"; finalValue: number };

export class AssetError extends Error {
  constructor(public readonly code: string) { super(code); }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const assetDecider: Decider<AssetCommand, AssetEvent, AssetState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "register":
        if (s.status !== "none") throw new AssetError("ALREADY_REGISTERED");
        if (c.value < 0) throw new AssetError("NEGATIVE_VALUE");
        return [{ type: "AssetRegistered", id: c.id, value: c.value }];
      case "revalue":
        if (s.status !== "active") throw new AssetError("NOT_ACTIVE");
        if (c.value < 0) throw new AssetError("NEGATIVE_VALUE");
        return [{ type: "AssetRevalued", value: c.value }];
      case "retire":
        if (s.status !== "active") throw new AssetError("NOT_ACTIVE");
        return [{ type: "AssetRetired", finalValue: s.value }];
      default: { const _n: never = c; throw new AssetError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "AssetRegistered":
        return { status: "active", id: e.id, value: e.value };
      case "AssetRevalued":
        if (s.status !== "active") return s;
        return { ...s, value: e.value };
      case "AssetRetired":
        if (s.status !== "active") return s;
        return { status: "retired", id: s.id, finalValue: e.finalValue };
      default: { const _n: never = e; return s; }
    }
  },
};

