export type CampaignState =
  | { status: "draft" }
  | { status: "running"; id: string; name: string }
  | { status: "paused"; id: string; name: string }
  | { status: "ended"; id: string };

export type CampaignCommand =
  | { type: "launch"; id: string; name: string }
  | { type: "pause" }
  | { type: "resume" }
  | { type: "end" };

export type CampaignEvent =
  | { type: "CampaignLaunched"; id: string; name: string }
  | { type: "CampaignPaused" }
  | { type: "CampaignResumed" }
  | { type: "CampaignEnded" };

export class CampaignError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const campaignDecider: Decider<CampaignCommand, CampaignEvent, CampaignState> = {
  initialState: { status: "draft" },
  decide(c, s) {
    switch (c.type) {
      case "launch":
        if (s.status !== "draft") throw new CampaignError("ALREADY_LAUNCHED");
        if (c.name.length === 0) throw new CampaignError("INVALID_NAME");
        return [{ type: "CampaignLaunched", id: c.id, name: c.name }];
      case "pause":
        if (s.status !== "running") throw new CampaignError("NOT_RUNNING");
        return [{ type: "CampaignPaused" }];
      case "resume":
        if (s.status !== "paused") throw new CampaignError("NOT_PAUSED");
        return [{ type: "CampaignResumed" }];
      case "end":
        if (s.status === "draft" || s.status === "ended") throw new CampaignError("CANNOT_END");
        return [{ type: "CampaignEnded" }];
      default: { const _n: never = c; throw new CampaignError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "CampaignLaunched":
        return { status: "running", id: e.id, name: e.name };
      case "CampaignPaused":
        if (s.status !== "running") return s;
        return { status: "paused", id: s.id, name: s.name };
      case "CampaignResumed":
        if (s.status !== "paused") return s;
        return { status: "running", id: s.id, name: s.name };
      case "CampaignEnded":
        if (s.status === "draft" || s.status === "ended") return s;
        return { status: "ended", id: s.id };
      default: { const _n: never = e; return s; }
    }
  },
};

