export type LoanBookEvent =
  | { type: "LoanOriginated"; id: string; principal: number }
  | { type: "LoanDisbursed"; id: string; at: string }
  | { type: "LoanClosed"; id: string; reason: string };

export type LoanBookView = Readonly<{
  loans: ReadonlyArray<{ id: string; principal: number; status: "originated" | "disbursed" | "closed" }>;
}>;

export const emptyView: LoanBookView = { loans: [] };

export function project(view: LoanBookView, event: LoanBookEvent): LoanBookView {
  switch (event.type) {
    case "LoanOriginated":
      return { loans: [...view.loans, { id: event.id, principal: event.principal, status: "originated" }] };
    case "LoanDisbursed":
      return { loans: view.loans.map((l) => (l.id === event.id ? { ...l, status: "disbursed" } : l)) };
    case "LoanClosed":
      return { loans: view.loans.map((l) => (l.id === event.id ? { ...l, status: "closed" } : l)) };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

