export type PortfolioProjEvent =
  | { type: "PortfolioOpened"; id: string }
  | { type: "HoldingAdded"; id: string; units: number }
  | { type: "PortfolioClosed"; id: string }
  | { type: "UnrelatedAudit"; note: string };

export type PortfolioSummaryView = Readonly<Record<string, { totalUnits: number; closed: boolean }>>;

export const emptyView: PortfolioSummaryView = {};

export function project(view: PortfolioSummaryView, event: PortfolioProjEvent): PortfolioSummaryView {
  switch (event.type) {
    case "PortfolioOpened":
      return { ...view, [event.id]: { totalUnits: 0, closed: false } };
    case "HoldingAdded": {
      const current = view[event.id] ?? { totalUnits: 0, closed: false };
      return { ...view, [event.id]: { ...current, totalUnits: current.totalUnits + event.units } };
    }
    case "PortfolioClosed": {
      const current = view[event.id];
      if (!current) return view;
      return { ...view, [event.id]: { ...current, closed: true } };
    }
    case "UnrelatedAudit":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

