```typescript
export interface PositionStateV1 { id: string; qty: number; }
export interface PositionStateV2 { id: string; qty: number; symbol: string; }
export interface PositionStateV3 { id: string; qty: number; symbol: string; avgCost: number; }

export type CurrentState = PositionStateV3;
export const CURRENT_VERSION = 3;

export interface Snapshot<S> { version: number; state: S; }

function v1Tov2(prev: PositionStateV1): PositionStateV2 {
  return { id: prev.id, qty: prev.qty, symbol: "UNKNOWN" };
}

function v2Tov3(prev: PositionStateV2): PositionStateV3 {
  return { id: prev.id, qty: prev.qty, symbol: prev.symbol, avgCost: 0 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) {
    state = v1Tov2(state as PositionStateV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as PositionStateV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error("UNKNOWN_SNAPSHOT_VERSION");
  return { version, state: state as CurrentState };
}

export function loadSnapshot(raw: Snapshot<unknown>): CurrentState {
  const upgraded = upgradeSnapshot(raw);
  return upgraded.state;
}

