export type LoanEvent =
  | { type: "LoanOriginated"; id: string; principal: number }
  | { type: "LoanDisbursed"; at: string };

export interface EventStore {
  readStream(stream: string): Promise<{ revision: bigint; events: LoanEvent[] }>;
  appendToStream(
    stream: string,
    events: LoanEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) { super(`Conflict on ${stream}`); }
}

export async function appendLoan(
  store: EventStore,
  stream: string,
  newEvents: LoanEvent[],
): Promise<bigint> {
  const { revision, events } = await store.readStream(stream);
  const expectedRevision: bigint | "no_stream" = events.length === 0 ? "no_stream" : revision;
  try {
    const { nextExpectedRevision } = await store.appendToStream(stream, newEvents, { expectedRevision });
    return nextExpectedRevision;
  } catch (err) {
    const e = err as { code?: string };
    if (e.code === "WrongExpectedVersion") throw new ConcurrencyConflict(stream);
    throw err;
  }
}

