    stream: string,
    events: PortfolioEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string) { super(`Conflict on ${stream}`); }
}

export async function appendWithRetry(
  store: EventStore,
  stream: string,
  build: (events: PortfolioEvent[]) => PortfolioEvent[],
  maxAttempts = 3,
): Promise<bigint> {
  let attempt = 0;
  while (attempt < maxAttempts) {
    const { revision, events } = await store.readStream(stream);
    const expectedRevision: bigint | "no_stream" = events.length === 0 ? "no_stream" : revision;
    const newEvents = build(events);
    try {
      const r = await store.appendToStream(stream, newEvents, { expectedRevision });
      return r.nextExpectedRevision;
    } catch (err) {
      const e = err as { code?: string };
      if (e.code !== "WrongExpectedVersion") throw err;
      attempt += 1;
    }
  }
  throw new ConcurrencyConflict(stream);
}

