  switch (event.type) {
    case "CampaignLaunched":
      return { ...view, launched: [...view.launched, event.id] };
    case "CampaignPaused":
      return { ...view, paused: [...view.paused, event.id] };
    default: { const _n: never = event; return view; }
  }
