  name: string,
  store: CheckpointStore,
  stream: AsyncIterable<EventEnvelope<CampaignEvent>>,
  apply: (view: CampaignView) => Promise<void>,
): Effect.Effect<void, Error> =>
  Effect.gen(function* () {
    const startFrom = yield* Effect.tryPromise({
      try: () => store.read(name),
      catch: (e) => e as Error,
    });
    let view = emptyView;
    let position = startFrom ?? 0n;
    for await (const envelope of stream) {
      if (envelope.position <= position) continue;
      view = project(view, envelope.event);
      yield* Effect.tryPromise({ try: () => apply(view), catch: (e) => e as Error });
      yield* Effect.tryPromise({
        try: () => store.write(name, envelope.position),
        catch: (e) => e as Error,
