export type PositionEvent =
  | { type: "PositionOpened"; id: string; qty: number }
  | { type: "QuantityIncreased"; qty: number }
  | { type: "QuantityDecreased"; qty: number }
  | { type: "PositionClosed" };

export type Position = Readonly<{ id: string; qty: number; closed: boolean }>;

export function when(state: Partial<Position>, event: PositionEvent): Partial<Position> {
  switch (event.type) {
    case "PositionOpened":
      return { id: event.id, qty: event.qty, closed: false };
    case "QuantityIncreased":
      return { ...state, qty: (state.qty ?? 0) + event.qty };
    case "QuantityDecreased":
      return { ...state, qty: (state.qty ?? 0) - event.qty };
    case "PositionClosed":
      return { ...state, closed: true };
    default: { const _n: never = event; return state; }
  }
}

export function isPosition(s: Partial<Position>): s is Position {
  return !!s.id && typeof s.qty === "number" && typeof s.closed === "boolean";
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  reducer: (s: Partial<S>, e: E) => Partial<S>,
  check: (s: Partial<S>) => s is S,
): Promise<S> {
  let state: Partial<S> = {};
  for await (const event of stream) {
    state = reducer(state, event);
  }
  if (!check(state)) throw new Error("INVALID_AGGREGATE_STATE");
  return state;
}

export const positionFromStream = (stream: AsyncIterable<PositionEvent>): Promise<Position> =>
  aggregateStream(stream, when, isPosition);

