  readForward(from: bigint, batchSize: number): Promise<EventEnvelope[]>;
}

export type AuditView = Readonly<Record<string, ReadonlyArray<string>>>;

export const emptyView: AuditView = {};

export function project(view: AuditView, event: AuditEvent): AuditView {
  switch (event.type) {
    case "AuditStarted":
      return { ...view, [event.id]: [] };
    case "FindingRecorded": {
      const existing = view[event.id] ?? [];
      return { ...view, [event.id]: [...existing, event.detail] };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface RebuildOptions {
  readonly from: bigint;
  readonly batchSize: number;
  readonly store: EventStoreIterator;
  readonly persist: (view: AuditView, cursor: bigint) => Promise<void>;
}

export async function rebuild(opts: RebuildOptions): Promise<void> {
  let cursor = opts.from;
  let view: AuditView = emptyView;
  for (;;) {
    const batch = await opts.store.readForward(cursor, opts.batchSize);
    if (batch.length === 0) break;
    for (const env of batch) {
      view = project(view, env.event);
      cursor = env.revision;
    }
    await opts.persist(view, cursor);
  }
}

