  switch (event.type) {
    case "MortgageApplied":
      return { type: "RunCreditCheck", id: event.id, amount: event.amount };
    case "CreditCheckPassed":
      return { type: "ApproveMortgage", id: event.id };
    case "CreditCheckFailed":
      return { type: "RejectMortgage", id: event.id, reason: event.reason };
    case "MortgageApproved":
      return null;
    default: {
      const _n: never = event;
      return null;
    }
  }
}

// Helper: run the process manager over a historical event stream, collecting
// the commands it would have emitted. Used in tests to verify saga evolve logic.
export function aggregate(events: MortgageEvent[]): MortgageCommand[] {
  const out: MortgageCommand[] = [];
  for (const event of events) {
    const cmd = react(event);
    if (cmd !== null) out.push(cmd);
  }
  return out;
