export type CampaignEvent =
  | { type: "CampaignLaunched"; id: string; name: string }
  | { type: "CampaignEnded"; id: string };

export interface OutboxRow {
  readonly id: string;
  readonly payload: string;
  readonly publishedAt: string | null;
}

export interface UnitOfWork {
  appendToStream(
    stream: string,
    events: CampaignEvent[],
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
  insertOutbox(row: OutboxRow): Promise<void>;
}

export interface Conn {
  transaction<T>(fn: (uow: UnitOfWork) => Promise<T>): Promise<T>;
}

// A separate publisher worker (not implemented here) would poll the outbox
// table for rows where publishedAt IS NULL, publish them to the bus, and
// update publishedAt once the broker acknowledges receipt.
export async function appendWithOutbox(
  conn: Conn,
  stream: string,
  events: CampaignEvent[],
  outboxRows: OutboxRow[],
  expectedRevision: bigint | "no_stream" | "any",
): Promise<bigint> {
  return conn.transaction(async (uow) => {
    for (const row of outboxRows) {
      await uow.insertOutbox(row);
    }
    const { nextExpectedRevision } = await uow.appendToStream(stream, events, { expectedRevision });
    return nextExpectedRevision;
  });
}

