export type HoldingEvent =
  | { type: "HoldingOpened"; id: string; symbol: string; units: number }
  | { type: "UnitsAdded"; units: number }
  | { type: "UnitsRemoved"; units: number }
  | { type: "HoldingClosed" };

export type HoldingState =
  | { status: "none" }
  | { status: "open"; id: string; symbol: string; units: number }
  | { status: "closed"; id: string };

// `decide` consumes a Command and current state; it validates invariants and
// returns Events. `evolve` consumes one Event and returns the next state. Only
// `evolve` is used when folding a stream; `decide` is used when accepting new
// commands. Both must be pure functions.
export const initialState: HoldingState = { status: "none" };

export function evolve(state: HoldingState, event: HoldingEvent): HoldingState {
  switch (event.type) {
    case "HoldingOpened":
      return { status: "open", id: event.id, symbol: event.symbol, units: event.units };
    case "UnitsAdded":
      if (state.status !== "open") return state;
      return { ...state, units: state.units + event.units };
    case "UnitsRemoved":
      if (state.status !== "open") return state;
      return { ...state, units: state.units - event.units };
    case "HoldingClosed":
      if (state.status !== "open") return state;
      return { status: "closed", id: state.id };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

