export type StrategyEvent =
  | { type: "StrategyDefined"; id: string; name: string }
  | { type: "StrategyActivated" }
  | { type: "StrategyDeactivated" };

export type StrategyState =
  | { status: "none" }
  | { status: "inactive"; id: string; name: string }
  | { status: "active"; id: string; name: string };

export const initialState: StrategyState = { status: "none" };

export function evolve(state: StrategyState, event: StrategyEvent): StrategyState {
  switch (event.type) {
    case "StrategyDefined":
      return { status: "inactive", id: event.id, name: event.name };
    case "StrategyActivated":
      if (state.status === "none") return state;
      return { status: "active", id: state.id, name: state.name };
    case "StrategyDeactivated":
      if (state.status === "none") return state;
      return { status: "inactive", id: state.id, name: state.name };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function aggregateStream(events: StrategyEvent[]): StrategyState {
  return events.reduce<StrategyState>(evolve, initialState);
}

